import React, { useState, useRef, useEffect, memo } from 'react';

const ChatBox = memo(({ messages, onSend, isOpen, onToggle, unread }) => {
    const [text, setText] = useState('');
    const listRef = useRef(null);

    useEffect(() => {
        if (listRef.current && isOpen) {
            listRef.current.scrollTop = listRef.current.scrollHeight;
        }
    }, [messages, isOpen]);

    const handleSend = () => {
        if (text.trim()) {
            onSend(text.trim());
            setText('');
        }
    };

    return (
        <div className={`fixed bottom-4 right-4 z-50 transition-all ${isOpen ? 'w-72 sm:w-80' : ''}`}>
            {isOpen ? (
                <div className="bg-slate-800 border border-slate-600 rounded-2xl shadow-2xl flex flex-col" style={{ height: '320px' }}>
                    <div className="flex items-center justify-between px-4 py-2 border-b border-slate-700">
                        <span className="font-bold text-sm text-white">💬 Chat</span>
                        <button onClick={onToggle} className="text-slate-400 hover:text-white text-lg leading-none">✕</button>
                    </div>
                    <div ref={listRef} className="flex-1 overflow-y-auto px-3 py-2 space-y-1.5 text-sm">
                        {messages.length === 0 && <p className="text-slate-500 text-center text-xs mt-8">No messages yet</p>}
                        {messages.map((m, i) => (
                            <div key={m.id || i} className={m.isSystem ? 'text-center' : `flex ${m.isMine ? 'justify-end' : 'justify-start'}`}>
                                {m.isSystem ? (
                                    <p className="text-slate-500 text-xs italic">{m.text}</p>
                                ) : (
                                    <div className={`rounded-lg px-2.5 py-1.5 max-w-[85%] break-words ${m.isMine ? 'bg-blue-600 text-white' : 'bg-slate-700 text-slate-200'}`}>
                                        {!m.isMine && <span className="text-xs font-bold text-yellow-300 block">{m.senderName}</span>}
                                        {m.text}
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                    <div className="p-2 border-t border-slate-700 flex gap-2">
                        <input
                            type="text"
                            value={text}
                            onChange={e => setText(e.target.value.slice(0, 200))}
                            onKeyDown={e => e.key === 'Enter' && handleSend()}
                            placeholder="Type a message…"
                            className="flex-1 px-3 py-1.5 bg-slate-700 border border-slate-600 rounded-lg text-white text-sm placeholder-slate-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
                            maxLength={200}
                        />
                        <button onClick={handleSend} disabled={!text.trim()} className="px-3 py-1.5 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white font-bold rounded-lg transition text-sm">
                            ➤
                        </button>
                    </div>
                </div>
            ) : (
                <button
                    onClick={onToggle}
                    className="bg-blue-600 hover:bg-blue-500 text-white p-3 rounded-full shadow-lg transition-all hover:scale-110 relative"
                >
                    💬
                    {unread > 0 && (
                        <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[0.6rem] font-bold w-5 h-5 flex items-center justify-center rounded-full animate-pulse">
                            {unread > 9 ? '9+' : unread}
                        </span>
                    )}
                </button>
            )}
        </div>
    );
});

ChatBox.displayName = 'ChatBox';
export default ChatBox;
